```class Solution {
public:
    int racecar(int target) {
        queue<pair<int, int>> q;
        q.push({0, 1});
        unordered_set<int> vis;
        vis.insert(0);
        int res = 0;
        while (!q.empty()) {
            int sz = q.size();
            for (int i = 0; i < sz; i++) {
                int pos = q.front().first;
                int speed = q.front().second;
                q.pop();
                if (pos == target) return res;
                if (pos + speed < 0 || pos + speed > target * 2) continue;
                if (!vis.count(pos + speed)) {
                    vis.insert(pos + speed);
                    q.push({pos + speed, speed * 2});
                }
                if (!vis.count(pos)) {
                    vis.insert(pos);
                    q.push({pos, -1});
                }
            }
            res++;
        }
        return -1;
    }
};
